const ALKANE_REFERENCE_RELATIVE_ABUNDANCE_THRESHOLD = 0.01

"""
    AlkaneStandard

Reference data used to identify an n-alkane ladder.

`spectra` contains one `MassSpectrum` per alkane. The built-in default standard is
created from C8-C40 spectra whose ions were retained when their base-peak-normalized
relative abundance was greater than 1%.
"""
struct AlkaneStandard{S,M}
    name::String
    spectra::S
    metadata::M
end

function alkane_reference_spectrum(
    carbon::Integer,
    label::AbstractString,
    ri::Real,
    mzs::AbstractVector{<:Integer},
    relative_abundances::AbstractVector{<:Real},
)
    MassSpectrum(
        collect(Int, mzs),
        collect(Float64, relative_abundances);
        attrs=(
            ri=Float64(ri),
            order=Int(carbon),
            label=String(label),
            source=:experimental_ladder_spectra,
            normalization=:base_peak,
            relative_abundance_threshold=ALKANE_REFERENCE_RELATIVE_ABUNDANCE_THRESHOLD,
        ),
    )
end

