const ALKANE_REFERENCE_SPECTRA = [
    alkane_reference_spectrum(data...) for data in ALKANE_REFERENCE_SPECTRUM_DATA
]

const DEFAULT_ALKANE_STANDARD = AlkaneStandard(
    "n-alkane C8-C40 reference spectra",
    ALKANE_REFERENCE_SPECTRA,
    (
        source=:experimental_ladder_spectra,
        carbon_range=8:40,
        normalization=:base_peak,
        relative_abundance_threshold=ALKANE_REFERENCE_RELATIVE_ABUNDANCE_THRESHOLD,
    ),
)

"""
    alkanereferencespectra() -> Vector{MassSpectrum}

Return copies of the built-in C8-C40 n-alkane reference spectra.
"""
alkanereferencespectra() = deepcopy(ALKANE_REFERENCE_SPECTRA)

"""
    alkanereferencespectrum(carbon::Integer) -> MassSpectrum

Return a copy of the built-in n-alkane reference spectrum for carbon number `carbon`.
"""
function alkanereferencespectrum(carbon::Integer)
    index = findfirst(s -> attrs(s).order == carbon, ALKANE_REFERENCE_SPECTRA)
    isnothing(index) && throw(ArgumentError(
        "no built-in n-alkane reference spectrum for carbon number $(carbon)"))

    deepcopy(ALKANE_REFERENCE_SPECTRA[index])
end

"""
    defaultalkanestandard() -> AlkaneStandard

Return the built-in C8-C40 n-alkane standard.
"""
defaultalkanestandard() = deepcopy(DEFAULT_ALKANE_STANDARD)
